const q = $.input.searchQuery;
const staticTerms = 'company about us team';
return { query: q + ' ' + staticTerms };

const results = $.steps.searchCompanies.response.results || [];
const companies = results.map((r, i) => ({
  index: i + 1,
  title: r.title || 'Unknown',
  url: r.url || '',
  snippet: (r.text || '').slice(0, 600)
})).filter(c => c.url.length > 0);
return { companies, count: companies.length };

const companies = $.steps.extractCompanies.output.companies || [];
const iterations = $.steps.scrapeCompanies.response.iterations || [];
let compiled = '';
companies.forEach((c, i) => {
  compiled += '--- COMPANY ' + c.index + ' ---\n';
  compiled += 'Name: ' + c.title + '\n';
  compiled += 'URL: ' + c.url + '\n';
  compiled += 'Snippet: ' + c.snippet + '\n';
  if (iterations[i] && iterations[i].scrapeOne && iterations[i].scrapeOne.response) {
    const s = iterations[i].scrapeOne.response;
    const content = (typeof s === 'string') ? s : JSON.stringify(s);
    compiled += 'Website: ' + content.slice(0, 2500) + '\n';
  }
  compiled += '\n';
});
return { compiled: compiled.slice(0, 30000), count: companies.length };

const d = $.steps.compileData.output;
const criteria = $.input.scoringCriteria;
let prompt = 'You are a business analyst. Score and qualify these companies based on the following criteria.\n\n';
prompt += 'SCORING CRITERIA: ' + criteria + '\n\n';
prompt += 'COMPANIES (' + d.count + '):\n';
prompt += d.compiled + '\n';
prompt += 'For each company, score 1-100 and classify as A (80+), B (50-79), or C (below 50).\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "companies": [{\n';
prompt += '    "name": "company name",\n';
prompt += '    "url": "website url",\n';
prompt += '    "score": 85,\n';
prompt += '    "grade": "A",\n';
prompt += '    "industry": "industry",\n';
prompt += '    "estimatedSize": "10-50|50-200|200-1000|1000+",\n';
prompt += '    "strengths": ["strength1", "strength2"],\n';
prompt += '    "notes": "brief analyst note"\n';
prompt += '  }],\n';
prompt += '  "summary": "pipeline summary",\n';
prompt += '  "topPicks": ["company1", "company2"]\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiScore.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { companies: [], summary: raw, topPicks: [] }; }

const ai = $.steps.parseAI.output;
const companies = ai.companies || [];
const header = ['Company', 'URL', 'Score', 'Grade', 'Industry', 'Est. Size', 'Strengths', 'Notes'];
const rows = companies.map(c => [
  c.name || 'Unknown',
  c.url || '',
  String(c.score || 0),
  c.grade || 'C',
  c.industry || '',
  c.estimatedSize || '',
  (c.strengths || []).join('; '),
  c.notes || ''
]);
return { values: [header].concat(rows), totalCompanies: companies.length, summary: ai.summary || '' };

const ai = $.steps.parseAI.output;
const companies = ai.companies || [];
const topPicks = ai.topPicks || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Company Scoring Complete', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + companies.length + ' companies* scored and added to CRM' } });

const gradeA = companies.filter(c => c.grade === 'A').length;
const gradeB = companies.filter(c => c.grade === 'B').length;
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Grade A:* ' + gradeA },
  { type: 'mrkdwn', text: '*Grade B:* ' + gradeB }
] });

if (topPicks.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Top Picks:* ' + topPicks.join(', ') } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Firecrawl + Claude AI' }] });

const fallback = 'Company Scoring: ' + companies.length + ' companies scored, ' + gradeA + ' Grade A';
return { blocks, fallback };
